INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 3.414, 1, 1, 62, -416.5, 0.0, "2030/01/01 14:59:59", 1000001, 2, 190801, "2025/01/31 12:00:00", 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ミッションをクリアして、\n報酬をゲットしましょう！", 3.099, 2, 1, 62, -416.5, 0.0, "2030/01/01 14:59:59", 1000002, 2, 190801, "2025/01/31 12:00:00", 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("受け取ることができる\n報酬があるようです\n確認してみてください", 2.801, 3, 1, 63, -416.5, 0.0, "2030/01/01 14:59:59", 1000003, 2, 190801, "2025/01/31 12:00:00", 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("報酬がもらえますよ！\nチェックしてみてください", 0.0, 4, 2, 63, -416.5, 0.0, "2030/01/01 14:59:59", 1000004, 2, 190801, "2025/01/31 12:00:00", 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 2.12, 5, 2, 64, -363.0, 0.0, "2030/01/01 14:59:59", 1000005, 1, 190801, "2025/01/31 12:00:00", 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1.68, 6, 1, 64, -363.0, 0.0, "2030/01/01 14:59:59", 1000006, 2, 190801, "2025/01/31 12:00:00", 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 2.33, 7, 2, 64, -363.0, 0.0, "2030/01/01 14:59:59", 1000007, 1, 190801, "2025/01/31 12:00:00", 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 5.18, 101, 3, 61, -285.0, -6.0, "2030/01/01 14:59:59", 1020101, 7, 133701, "2025/01/31 12:00:00", 10201, "ラビリスタ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 8.77, 201, 1, 61, -285.0, -2.0, "2030/01/01 14:59:59", 1020102, 2, 133901, "2025/01/31 12:00:00", 10201, "クリスティーナ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 15.5, 301, 6, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020103, 1, 133801, "2025/01/31 12:00:00", 10201, "ネネカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 9.061, 101, 2, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020201, 5, 134301, "2025/02/28 12:00:00", 10202, "ランファ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 7.699, 201, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020202, 2, 134401, "2025/02/28 12:00:00", 10202, "チカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 8.595, 101, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020301, 2, 134601, "2025/03/31 12:00:00", 10203, "アオイ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 7.758, 201, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020302, 2, 134501, "2025/03/31 12:00:00", 10203, "クローチェ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 7.0, 101, 2, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020401, 6, 132302, "2025/04/30 12:00:00", 10204, "ルイズマリー");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 7.904, 201, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020402, 2, 132402, "2025/04/30 12:00:00", 10204, "イロハ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 8.487, 301, 4, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020403, 2, 132502, "2025/04/30 12:00:00", 10204, "ソノ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 8.763, 101, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020502, 2, 134901, "2025/05/31 12:00:00", 10205, "カノン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 6.417, 201, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020503, 3, 134801, "2025/05/31 12:00:00", 10205, "ツムギ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 10.335, 101, 3, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020601, 7, 135001, "2025/06/30 12:00:00", 10206, "エリス");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 6.281, 201, 2, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020602, 4, 135101, "2025/06/30 12:00:00", 10206, "シェフィ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 12.244, 301, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020603, 2, 135201, "2025/06/30 12:00:00", 10206, "プレシア");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 6.339, 101, 2, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020701, 8, 135301, "2025/07/31 12:00:00", 10207, "クリア");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 8.184, 201, 7, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020702, 9, 135401, "2025/07/31 12:00:00", 10207, "アネモネ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 3.906, 101, 9, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020801, 2, 129101, "2025/08/31 12:00:00", 10208, "アイラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 14.465, 201, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020802, 2, 129201, "2025/08/31 12:00:00", 10208, "シナツ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 8.662, 301, 4, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020803, 3, 100101, "2025/08/31 12:00:00", 10208, "ヒヨリ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 10.915, 401, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020804, 3, 100301, "2025/08/31 12:00:00", 10208, "レイ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 6.042, 101, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020901, 7, 135802, "2025/09/30 12:00:00", 10209, "ユキノ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 9.402, 201, 4, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020902, 1, 135903, "2025/09/30 12:00:00", 10209, "サツキ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 8.16, 301, 8, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1020903, 1, 136902, "2025/09/30 12:00:00", 10209, "ルルィ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 5.0, 101, 3, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021001, 2, 137401, "2025/10/31 12:00:00", 10210, "カスミ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 8.12, 201, 4, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021002, 1, 136001, "2025/10/31 12:00:00", 10210, "アラクネ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 6.386, 301, 4, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021003, 2, 136202, "2025/10/31 12:00:00", 10210, "ナーナ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 7.438, 101, 3, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021101, 4, 136402, "2025/11/30 12:00:00", 10211, "ユイ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 8.35, 201, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021102, 5, 136302, "2025/11/30 12:00:00", 10211, "ミソラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 5.0, 101, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021201, 2, 136501, "2025/12/31 12:00:00", 10212, "シズル");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 5.25, 201, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021202, 2, 137902, "2025/12/31 12:00:00", 10212, "リノ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 7.5, 301, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021203, 2, 106801, "2025/12/31 12:00:00", 10212, "ラビリスタ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 8.204, 101, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021301, 2, 126501, "2026/01/31 12:00:00", 10213, "ライラエル");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 7.176, 201, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021302, 2, 129701, "2026/01/31 12:00:00", 10213, "ネフィ＝ネラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 8.602, 301, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021303, 5, 133101, "2026/01/31 12:00:00", 10213, "ヴァイオレット");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 10.14, 102, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021304, 3, 138101, "2026/02/06 12:00:00", 10213, "ライラエル");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 10.152, 202, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021305, 7, 138201, "2026/02/06 12:00:00", 10213, "ネフィ＝ネラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 9.688, 302, 4, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021306, 3, 138001, "2026/02/06 12:00:00", 10213, "ヴァイオレット");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 5.928, 401, 2, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021307, 1, 138301, "2026/02/12 12:00:00", 10213, "ペコリーヌ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 9.19, 101, 4, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021401, 2, 138702, "2026/02/28 12:00:00", 10214, "ワカナ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 8.724, 201, 1, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021402, 3, 138802, "2026/02/28 12:00:00", 10214, "シオリ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 7.758, 101, 4, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021501, 1, 138902, "2026/03/31 12:00:00", 10215, "グレイス");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 6.375, 201, 6, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021502, 4, 139002, "2026/03/31 12:00:00", 10215, "キョウカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 6.173, 301, 6, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021503, 1, 136902, "2026/03/31 12:00:00", 10215, "ルルィ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", 4.202, 101, 6, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021601, 2, 139202, "2026/04/30 12:00:00", 10216, "ミホ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", 2.842, 201, 6, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021602, 1, 139302, "2026/04/30 12:00:00", 10216, "マホ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", 4.598, 301, 4, 61, -285.0, 0.0, "2030/01/01 14:59:59", 1021603, 1, 139402, "2026/04/30 12:00:00", 10216, "エリカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 3.414, 1, 1, 62, -416.5, 0.0, "2030/01/01 14:59:59", 2000001, 2, 190801, "2026/04/10 12:00:00", 2, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ミッションをクリアして、\n報酬をゲットしましょう！", 3.099, 2, 1, 62, -416.5, 0.0, "2030/01/01 14:59:59", 2000002, 2, 190801, "2026/04/10 12:00:00", 2, "カリン");
