INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 2.12, 5, 2, 64, -363.0, 0.0, "2030/01/01 14:59:59", 2000005, 1, 190801, "2026/04/10 12:00:00", 2, "カリン");
