INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 2.33, 7, 2, 64, -363.0, 0.0, "2030/01/01 14:59:59", 2000007, 1, 190801, "2026/04/10 12:00:00", 2, "カリン");
